class Solution:
    def findLatestStep(self, arr, m):
        n = len(arr)
        bits = [0] * n
        ans = -1
        for step, pos in enumerate(arr, start=1):
            bits[pos - 1] = 1
            run = 0
            found = False
            for b in bits:
                if b == 1:
                    run += 1
                else:
                    if run == m:
                        found = True
                    run = 0
            if run == m:
                found = True
            if found:
                ans = step
        return ans

